import{_ as o,o as i,c as t,ah as a}from"./chunks/framework.Bi9enVNS.js";const m=JSON.parse('{"title":"Current Limits","description":"","frontmatter":{},"headers":[],"relativePath":"en/intro/limits.md","filePath":"en/intro/limits.md","lastUpdated":1774205896000}'),n={name:"en/intro/limits.md"};function r(l,e,d,s,c,u){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="current-limits" tabindex="-1">Current Limits <a class="header-anchor" href="#current-limits" aria-label="Permalink to &quot;Current Limits&quot;">​</a></h1><p>This page documents what the implementation does not provide yet.</p><h2 id="storage-and-durability" tabindex="-1">Storage and durability <a class="header-anchor" href="#storage-and-durability" aria-label="Permalink to &quot;Storage and durability&quot;">​</a></h2><ul><li>Only an in-memory store is implemented</li><li>Data disappears when the process restarts</li><li>There is no indexing, sharding, or storage tiering</li></ul><h2 id="ingestion-and-authorization" tabindex="-1">Ingestion and authorization <a class="header-anchor" href="#ingestion-and-authorization" aria-label="Permalink to &quot;Ingestion and authorization&quot;">​</a></h2><ul><li>There is only one ingestion endpoint: <code>POST /v1/logs</code></li><li>Only Bearer token authorization is implemented</li><li>Tokens are authorized at the project level only</li></ul><h2 id="query-behavior" tabindex="-1">Query behavior <a class="header-anchor" href="#query-behavior" aria-label="Permalink to &quot;Query behavior&quot;">​</a></h2><ul><li>All query endpoints return JSON</li><li>Log search supports only fixed query fields</li><li><code>keyword</code> matches <code>body_text + body_json</code> only, not attributes or resource</li><li>There is no pagination or configurable sort order</li></ul><h2 id="trace-and-topology-semantics" tabindex="-1">Trace and topology semantics <a class="header-anchor" href="#trace-and-topology-semantics" aria-label="Permalink to &quot;Trace and topology semantics&quot;">​</a></h2><ul><li>Topology is not a span graph; it is inferred from adjacent source segments inside a trace</li><li>Consecutive identical source segments are collapsed to avoid accidental self-loops</li><li><code>observed_time</code> is accepted by the protocol but is not exposed in current normalized query outputs</li></ul><h2 id="idempotency-and-caching" tabindex="-1">Idempotency and caching <a class="header-anchor" href="#idempotency-and-caching" aria-label="Permalink to &quot;Idempotency and caching&quot;">​</a></h2><ul><li>The idempotency window is process-local</li><li>TTL is fixed at 24 hours</li><li>The idempotency key is <code>project + request_id</code></li></ul><h2 id="frontend-and-deployment" tabindex="-1">Frontend and deployment <a class="header-anchor" href="#frontend-and-deployment" aria-label="Permalink to &quot;Frontend and deployment&quot;">​</a></h2><ul><li>The current frontend defaults to <code>http://localhost:8080</code></li><li>This documentation does not add CI/CD or production deployment guidance</li></ul><h2 id="sources-of-truth" tabindex="-1">Sources of truth <a class="header-anchor" href="#sources-of-truth" aria-label="Permalink to &quot;Sources of truth&quot;">​</a></h2><ul><li><code>README.md</code></li><li><code>internal/config/config.go</code></li><li><code>internal/ingest/service.go</code></li><li><code>internal/ingest/normalize.go</code></li><li><code>internal/store/memory/memory.go</code></li></ul>',16)])])}const p=o(n,[["render",r]]);export{m as __pageData,p as default};
